(window.webpackJsonp=window.webpackJsonp||[]).push([[10],{446:function(t,v,_){"use strict";_.r(v);var r=_(36),e=Object(r.a)({},(function(){var t=this,v=t.$createElement,_=t._self._c||v;return _("ContentSlotsDistributor",{attrs:{"slot-key":t.$parent.slotKey}},[_("center",[t._v("\n  人生到处知何似，应似飞鸿踏雪泥："),_("br"),t._v("\n  泥上偶然留指爪，鸿飞那复计东西。"),_("br"),t._v("\n  老僧已死成新塔，坏壁无由见旧题。"),_("br"),t._v("\n  往日崎岖还记否，路长人困蹇驴嘶。\n")]),t._v(" "),_("h2",{attrs:{id:"译文"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#译文"}},[t._v("#")]),t._v(" 译文")]),t._v(" "),_("ul",[_("li",[t._v("人生在世，到这里、又到那里，偶然留下一些痕迹，你觉得像是什么？我看真像随处乱飞的鸿鹄，偶然在某处的雪地上落一落脚一样。")]),t._v(" "),_("li",[t._v("它在这块雪地上留下一些爪印，正是偶然的事，因为鸿鹄的飞东飞西根本就没有一定。")]),t._v(" "),_("li",[t._v("老和尚奉闲已经去世，他留下的只有一座藏骨灰的新塔，我们也没有机会再到那儿去看看当年题过字的破壁了。老和尚的骨灰塔和我们的题壁，是不是同飞鸿在雪地上偶然留下的爪印差不多呢！")]),t._v(" "),_("li",[t._v("你还记得当时往渑池的崎岖旅程吗？路又远，人又疲劳，驴子也累得直叫。")])]),t._v(" "),_("h2",{attrs:{id:"赏析"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#赏析"}},[t._v("#")]),t._v(" 赏析")]),t._v(" "),_("blockquote",[_("p",[t._v("前四句一气贯串，自由舒卷，超逸绝伦，散中有整，行文自然。首联两句，以雪泥鸿爪比喻人生。一开始就发出感喟，有发人深思、引人入胜的作用，并挑起下联的议论。")])]),t._v(" "),_("p",[t._v("“泥上偶然留指爪，鸿飞那复计东西。”当飞鸿远去之后，除了在雪泥上偶然留下几处爪痕之外，又有谁会管它是要向东还是往西呢。作者结合生活中的情景发出对人生的见解。用雪泥、鸿爪作喻，较之一般叙事文字直叙人生飘泊不定、匆匆无常要形象、蕴藉得多。根据清人查慎行《苏诗补注》记载，这个比喻是化用《景德传灯录》中天衣义怀禅师的话：“雁过长空，影沉寒水，雁无遗迹之意，水无留影之心。”苏轼的比喻非常生动、深刻，在宋代即被人称道，并被作为诗人“长于譬喻”的例证之一。“雪泥鸿爪”这个成语也就一直流传至今。次联两句又以“泥”“鸿”领起，用顶针格就“飞鸿踏雪泥”发挥。鸿爪留印属偶然，鸿飞东西乃自然。偶然故无常，人生如此，世事亦如此。他用巧妙的比喻，把人生看作漫长的征途，所到之处，诸如曾在渑池住宿、题壁之类，就像万里飞鸿偶然在雪泥上留下爪痕，接着就又飞走了；前程远大，这里并非终点。人生的遭遇既为偶然，则当以顺适自然的态度去对待人生。果能如此，怀旧便可少些感伤，处世亦可少些烦恼。苏轼的人生观如此，其劝勉爱弟的深意亦如此。此种亦庄亦禅的人生哲学，符合古代士大夫的普遍命运，亦能宽解古代士大夫的共同烦恼，所以流布广泛而久远。")]),t._v(" "),_("p",[t._v("前四句不但理趣十足，从写作手法上来看，也颇有特色。纪昀评道：“前四句单行入律，唐人旧格；而意境恣逸，则东坡之本色。”")]),t._v(" "),_("p",[t._v("后四句照应“怀旧”诗题，以叙事之笔，深化雪泥鸿爪的感触。")]),t._v(" "),_("p",[t._v("五、六句言僧死壁坏，故人不可见，旧题无处觅，见出人事无常，是“雪泥”、“指爪”感慨的具体化。尾联是针对苏辙原诗“遥想独游佳味少，无言骓马但鸣嘶”而引发的往事追溯。回忆当年旅途艰辛，有珍惜现在勉励未来之意，因为人生的无常，更显人生的可贵。艰难的往昔，化为温情的回忆，而如今兄弟俩都中了进士，前途光明，更要珍重如今的每一时每一事了。在这首早期作品中，诗人内心强大、达观的人生底蕴已经得到了展示。")]),t._v(" "),_("p",[t._v("全诗悲凉中有达观，低沉中有昂扬，读完并不觉得人生空幻，反有一种眷恋之情荡漾心中，犹如冬夜微火。于“怀旧”中展望未来，意境阔远。诗中既有对人生来去无定的怅惘，又有对前尘往事的深情眷念。")]),t._v(" "),_("p",[t._v("此诗的重心在前四句，而前四句的感受则具体地表现在后四句之中，从中可以看出诗人先前的积极人生态度，以及后来处在颠沛之中的乐观精神的底蕴。全篇圆转流走，一气呵成，涌动着散文的气脉，是苏轼的名作之一")])],1)}),[],!1,null,null,null);v.default=e.exports}}]);